#include<stdio.h>

typedef long long ll;
ll fox(ll a,ll b);
ll gcd(ll a,ll b);


int main()
{
  ll a,b,c,d;

  scanf("%lld%lld",&a,&b);

  d = (a>b)?gcd(a,b):gcd(b,a);

  c = fox(a/d,b/d);

  printf("%lld",c);

  return 0;

}


ll gcd(ll a,ll b)
{
 if(b==(ll)0)
   return a;

 return gcd(b,a%b);
}


ll fox(ll a,ll b)
{
 static ll count = (ll)0;
 ll larger,smaller;

 if(a==b)
   return count;

 count += (ll)1;

 if(a>b)
  {
    larger = a,smaller = b;
  }

 else
  {
    smaller = a,larger = b;
  }

 if(larger % (ll)2==(ll)0)
  {
   if(larger==a)
     a/=(ll)2;

   else
     b/=(ll)2;

   return fox(a,b);
  }

 else if(larger % (ll)3==(ll)0)
  {
   if(larger == a)
     a/=(ll)3;

   else
     b/=(ll)3;

   return fox(a,b);
  }

 else if(larger % (ll)5==(ll)0)
  {
   if(larger == a)
     a/=(ll)5;

   else
     b/=(ll)5;

   return fox(a,b);
  }

 else
   return -1;

}

