use std::io;
use std::mem::swap;
use std::str;

fn has_valid_prime_factors(n: i64) -> bool {
    let mut n = n;
    while n % 2 == 0 {
        n /= 2;
    }
    while n % 3 == 0 {
        n /= 3;
    }
    while n % 5 == 0 {
        n /= 5;
    }
    n == 1
}

fn gcd(a: i64, b: i64) -> i64 {
    if b == 0 {
        a
    } else {
        gcd(b, a % b)
    }
}

fn factorize(n: i64) -> Vec<(i64, i64)> {
    let mut n = n;
    let mut p = 2;
    let mut ans = Vec::new();
    while p * p <= n && n > 1 {
        let mut expo = 0;
        while n % p == 0 {
            expo += 1;
            n /= p;
        }
        if expo > 0 {
            ans.push((p, expo));
        }
        p += 1;
    }
    if n > 1 {
        ans.push((n, 1));
    }
    ans
}

fn solve<R: io::BufRead, W: io::Write>(scan: &mut Scanner<R>, out: &mut W) {
    let mut a: i64 = scan.token();
    let mut b: i64 = scan.token();
    if a > b {
        swap(&mut a, &mut b);
    }

    // a and b must be reduced each to its gcd.
    // a should become gcd(a, b) only dividing it by 2, 3 or 5.
    // b should become gcd(a, b) only dividing it by 2, 3 or 5.
    // In other words, a / gcd(a, b) and b / gcd(a, b) must only have 2, 3 or 5 as prime factors.
    let g = gcd(a, b);
    if a == b || (has_valid_prime_factors(a / g) && has_valid_prime_factors(b / g)) {
        let factors_without_gcd = factorize((a / g) * (b / g));
        let ans = factors_without_gcd.iter().fold(0i64, |acc, val| acc + val.1);
        writeln!(out, "{}", ans).ok();
    } else {
        writeln!(out, "-1").ok();
    }
}

fn main() {
    let (stdin, stdout) = (io::stdin(), io::stdout());
    let mut scan = Scanner::new(stdin.lock());
    let mut out = io::BufWriter::new(stdout.lock());
    solve(&mut scan, &mut out);
}

pub struct Scanner<R> {
    reader: R,
    buffer: Vec<String>,
}

impl<R: io::BufRead> Scanner<R> {
    pub fn new(reader: R) -> Self {
        Self {
            reader,
            buffer: vec![],
        }
    }

    pub fn token<T: str::FromStr>(&mut self) -> T {
        loop {
            if let Some(token) = self.buffer.pop() {
                return token.parse().ok().expect("Failed parse");
            }
            let mut input = String::new();
            self.reader.read_line(&mut input).expect("Failed read");
            self.buffer = input.split_whitespace().rev().map(String::from).collect();
        }
    }

    pub fn tokens<T: str::FromStr>(&mut self) -> Vec<T> {
        assert!(self.buffer.is_empty());
        let mut input = String::new();
        self.reader.read_line(&mut input).expect("Failed read");
        input
            .split_whitespace()
            .map(|x| x.parse().ok().expect("Failed parse"))
            .collect()
    }
}
